import os
import json
import numpy as np
import librosa
import soundfile as sf

def calculate_rms(y):
    return np.sqrt(np.mean(y**2))

def to_db(amplitude):
    if amplitude <= 1e-10:
        return -200.0
    return 20 * np.log10(amplitude)

def from_db(db):
    return 10 ** (db / 20)

def main():
    input_dir = "/workspace/inputs"
    output_dir = "/workspace/outputs"
    report_file = "/workspace/report.json"

    os.makedirs(output_dir, exist_ok=True)

    report = {}
    target_rms_db = -20.0
    target_rms_linear = from_db(target_rms_db)

    if not os.path.exists(input_dir):
        print(f"Input directory {input_dir} does not exist.")
        return

    for filename in os.listdir(input_dir):
        if not filename.lower().endswith(".wav"):
            continue

        input_path = os.path.join(input_dir, filename)
        output_path = os.path.join(output_dir, filename)

        y, sr = librosa.load(input_path, sr=None, mono=False)

        orig_rms_linear = calculate_rms(y)
        orig_rms_db = to_db(orig_rms_linear)

        if orig_rms_linear > 0:
            gain_linear = target_rms_linear / orig_rms_linear
        else:
            gain_linear = 1.0

        peak_linear = np.max(np.abs(y))

        if peak_linear * gain_linear > 1.0:
            gain_linear = 1.0 / peak_linear

        gain_db = to_db(gain_linear)

        y_normalized = y * gain_linear

        final_rms_linear = calculate_rms(y_normalized)
        final_rms_db = to_db(final_rms_linear)
        peak_after = float(np.max(np.abs(y_normalized)))

        if y_normalized.ndim > 1:
            y_out = y_normalized.T
        else:
            y_out = y_normalized

        sf.write(output_path, y_out, sr)

        report[filename] = {
            "orig_rms_db": float(orig_rms_db),
            "gain_db": float(gain_db),
            "final_rms_db": float(final_rms_db),
            "peak_after": peak_after
        }

    with open(report_file, "w") as f:
        json.dump(report, f, indent=4)

if __name__ == "__main__":
    main()

